INSERT INTO transfer_targets VALUES(30,'2026-summer','Tammy Abraham','타미 아브라함',610766,'Aston Villa','ST','ST','OWNED','01855255648X8415422010200',47.39999999999999858,59.0,4,6.849999999999999645,'st_target','Attack','st_false9','Attack',0.5210000000000000186,'ALREADY OWNED: 2026-01-27 베식타슈에서 ~£18m로 빌라 복귀(1일 만에 재이적), 그 시즌 유로파리그 우승. 여름 루머 대상이 아니라 보유 선수(알리송과 동일 케이스) — 사용자 요청으로 OWNED ST 옵션으로 편입. 실측(반시즌 통틀어 45분+ 4경기 전부 ST): 중앙-약간좌측·깊은 풋프린트 (47.4,59.0), 평균 6.85. 최근접 st_false9/Attack 0.52 — 왓킨스(st_advanced 자기커널)·기라시 0.80·브로베이 0.75·파르도 0.87보다 명확히 낮음. 처방은 타깃/홀드업 아키타입 반영 st_target/Attack. 표본 캐비앳: 왓킨스의 로테이션 백업이라 45분+ 경기가 반시즌 4경기뿐이고 전부 교체 출전(추격 상황 드롭) → 깊은 편향된 풋프린트, 선발 표본 아님. [2026-07-15 3축+스탯 — 유지] 6경기: xG .25·3골·kp 1.0·드리블 0 — 타깃형 피니셔, st_target/Attack(공중 플랜B, obs#19) 유지.','https://www.avfc.co.uk/news/2026/january/27/signing-aston-villa-confirm-tammy-abraham-signing/ ; SofaScore API player 610766 (2026-07-03)','OWNED — 이적 루머 아님(2026-01 합류확정 보유선수). 측정 신뢰 MEDIUM(표본 4경기·전부 교체출전·맥락 편향, 45분+ 6경기 미달).',NULL);
