INSERT INTO transfer_targets VALUES(58,'2026-summer','Eljif Elmas','엘리프 엘마스',838232,'RB Leipzig','M','CAM','MEDIUM-LOW','20123X5348656331322211110',47.60000000000000142,56.89999999999999858,6,6.599999999999999645,'cam_halfwinger','Balanced','cam_halfwinger','Balanced',0.8289999999999999592,'MEDIUM-HIGH — readastonvilla(2티어급) "가장 매력적인 선택지" + goonerdaily/caughtoffside 등 다수 매체 수렴: 페네르바흐체 제안 거절하고 빌라 선호 명확, CL 진출이 유인. RB라이프치히 buy option(€17m) 미행사로 이적 가능. 히트맵 MEDIUM-HIGH(나폴리 임대+국대 혼합 6경기). [2026-07-15 재확인] 프론트러너 지위 유지, 본인 빌라行 선호(페네르바흐체 거절) 재확인. RB라이프치히는 방출 의사, 협상 개시 준비 단계. [2026-07-15 3축+스탯 — focus 교정 Roaming→Balanced] 6경기 스탯: kp .8·xA .07·xG .09·패스 92% — 창조 산출 낮은 커넥터형(10번 창조 임무엔 약함, 캐비앗). 움직임 halfwinger/Balanced .829 >> Roaming .609(Δ.22) — Balanced로 교정. [2026-07-19 재검증] Romano 등 tier-1/2 어디에도 엘마스 언급 없음(직접 검색 확인). 6월초 이후 진전 소식 전무, TuttoMercatoWeb발 3티어만 순환 — 스테일.','https://readastonvilla.com/2026/06/05/aston-villa-transfer-eljif-elmas-rb-leipzig-2026/; https://goonerdaily.com/2026/06/06/aston-villa-lead-race-to-sign-eljif-elmas-after-midfielder-makes-premier-league-preference-clear/','MEDIUM-LOW — tier-1/2 크로스체크 실패, 기사 정체(6월초 이후 무소식). [2026-07-19 재검증 하향]','엘마스');
INSERT INTO transfer_targets VALUES(60,'2026-summer','Álex Remiro','알렉스 레미로',791773,'Real Sociedad','G','GK','MEDIUM','0000000000000000010001X10',49.79999999999999716,10.80000000000000072,6,6.820000000000000284,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.960999999999999966,'MEDIUM-HIGH — TeamTalk(2티어) "더블딜 가속화" 확인: 마르티네스 유벤투스 이적 임박에 맞춰 신규 GK 영입 후보로 부상, 크리스탈 팰리스·뉴캐슬·바르셀로나와 경쟁. 바이아웃 €50m→€12m로 급락. 히트맵 HIGH(라리가 단일클럽 6경기). [2026-07-15 재확인] Mundo Deportivo: 레미로가 경쟁 선두, 바이아웃 €50m→€12m로 급락. 소시에다드는 재계약 종용 중이나 빌라 공식 접촉은 아직. [2026-07-15 스탯 — 유지] 6경기: 선방 3.3/경기·패스 73%(후보군 상위 — 빌드업 신호 양호). 처방 유지. [2026-07-19 재검증] 소시에다드 스포츠디렉터(Bretos) "본인이 이적 의사 밝힌 적 없다" 진화, tier-1/2 협상 보도 전무 — 3티어만.','https://www.teamtalk.com/aston-villa/double-deal-accelerates-serhou-guirassy-signing-boost-alex-remiro-new-keeper-target; https://thehardtackle.com/transfer-news/2026/06/18/aston-villa-ahead-of-crystal-palace-newcastle-united-barcelona-in-alex-remiro-race/','MEDIUM — 12m 바이아웃으로 저가 옵션 유지되나 구단측 진화·tier-2+ 확인 부재. [2026-07-19 재검증 하향]','레미로');
INSERT INTO transfer_targets VALUES(61,'2026-summer','Jarrod Bowen',NULL,552884,'West Ham United','RW','RM','DEAD (웨스트햄 잔류 공언)','011261112X011140001300111',74.70000000000000284,62.70000000000000284,6,6.969999999999999752,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.9140000000000000346,'에머리가 다재다능성·주력·골 위협 높이 평가, 빌라 자산 매각 필요한 재정구조상 협상 미착수(웨스트햄 요구 £50m+) [2026-07-15 재확인] The Guardian(2티어): 첼시·에버턴과 경쟁 확인. £50m 요구가 여전히 부담, 웨스트햄 킷 캠페인으로 잔류 신호도 병존. [2026-07-15 실측] SofaScore 최근 6경기(PL, 45분+: 리즈·뉴캐슬·아스날·브렌트포드·에버턴·크리스탈팰리스) 히트맵 수집. 우측 고정(중심 74.7,62.7), wm_winger/Attack 커널과 코사인 0.89로 매우 높은 적합. [2026-07-15 3축+스탯 — 교정 winger/Attack→insidefwd/Balanced] 6경기 스탯: xA .18·kp 1.7·xG .12·듀얼 3.7 — 창조 우위 양방형(왼발 인버티드 커터). 움직임 insidefwd/Balanced .914 vs winger/Attack .89(Δ.024 동률권) — 기능축 타이브레이크로 insidefwd/Balanced. [2026-07-17 재확인] 본인이 강등에도 웨스트햄 잔류 공언("the vision is clear") — 링크 냉각, DEAD 처리.','The Athletic(Jacob Tanswell) via search-cross-check; teamtalk.com/aston-villa/jarrod-bowen-transfer-news (2티어 보조) (수집 2026-07-10) ; SofaScore API player 552884 (2026-07-15, PL 최근 6경기 45분+)','MEDIUM-HIGH — [2026-07-14 재확인] "빌라가 레이스 선두"(TeamTalk)이나 공식 오퍼는 아직 없음, £50m 가격표가 "선수 나이 대비 과함"이라는 빌라 내부 판단 보도. 첼시·에버턴·리버풀·뉴캐슬 등 다자 경쟁 지속. 등급 유지. / 2026-07-15 재확인: The Guardian(2티어) 첼시·에버턴 경쟁 확인, £50m 부담 지속. / 2026-07-17: 본인 잔류 공언으로 DEAD.','보웬');
INSERT INTO transfer_targets VALUES(65,'2026-summer','Robin Risser','리세르',1387161,'RC Lens','GK','GK','MEDIUM-HIGH','0000000000000000001001X30',52.70000000000000284,10.19999999999999928,6,6.633000000000000007,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.978999999999999982,'리그1 최근 6경기(45분+, 전경기 90분) 히트맵 240pt, 센트로이드 tool(52.7,10.2) — 중앙·자기골 근접, 전형적 라인 지키는 정통파. gk 커널 적합 gk_goalkeeper/Defend 0.978로 매우 높음(마르티네스 후속 대체자군과 동일 패턴). [2026-07-15 재확인] Athletic Tanswell(1티어): 레스테스가 여전히 1순위, 리세는 대안. 공식 오퍼 준비 단계. [2026-07-15 스탯 — 유지] 6경기: 선방 1.7/경기(랑스 지배 경기 다수)·패스 76%(후보군 1위 — 빌드업 GK 신호 최상). 처방 유지. [2026-07-19 재검증] tier-1/2(로마노/오른스틴/스카이/BBC/텔레그래프/타임스/가디언/버밍엄메일/팀토크) 확인 전무 — 프랑스지(L Equipe)·3티어만. 랑스 매각 저항 지속.','https://www.transferfeed.com/clubs/aston-villa/15(2026-07-11); L''Équipe(Loïc Tanzi) "preparing opening offer" 보도(2026-07-11 검색); SofaScore API player/1387161 (2026-07-11 수집)','MEDIUM-HIGH — 랑스가 오퍼 준비단계라는 프랑스지 보도, tier-1 미확인. [2026-07-19 재검증 하향]','리세르');
INSERT INTO transfer_targets VALUES(71,'2026-summer','Pedro Gonçalves','페드루 곤살베스',895764,'Sporting CP','AM','CAM','MEDIUM','542225X641431202122111100',37.39999999999999858,65.20000000000000284,6,6.879999999999999894,'cam_playmaker','Roaming','cam_playmaker','Roaming',0.7419999999999999929,'스포르팅·본인 모두 여름 이적 의사 확정(A Bola), 가격 €30m→€20-25m로 하향, 리버풀과 경쟁. 실측 결과 측면(RM)보다 중앙 공격형 미드필더(CAM) 적합도가 훨씬 높음(0.74 vs 0.23). 이벤트 스탯(같은 6경기 통합): 키패스 16(2.67/경기)·빅찬스 창출 2·xA 1.17(5경기 리포트분)·도움 2 — 창출력 우수. 반면 슛 16·유효슈팅 5·xG 0.61·득점 0 — 최근 표본에서 마무리는 xG 대비 부진. LM/LW 커널 재비교(0.702/0.667)도 CAM보다 낮아 실측·산출 모두 로저스형 박스크래셔가 아닌 중앙 크리에이터로 수렴. 슛맵(같은 6경기, 16슛): 박스 내 10/16(62.5%)·6야드 1개·헤더 0 — 헤더 전무는 박스크래셔/타겟형이 아님을 재확인. 평균 슈팅거리 15.8(골라인 기준, 박스 경계 부근)·평균 y 43.8(중앙 편향) — 중거리~박스 언저리에서 발로 마무리하는 전형적 중앙 크리에이터형 슈팅 패턴. [2026-07-15 재확인] A Bola: 스포르팅이 요구가 €40m→€20-25m로 급락, 조르지 멘드스가 직접 이적 추진. 리버풀도 경쟁. [2026-07-15 3축+스탯 — 유지] 6경기: kp 2.7·xA .19·패스 85% — 창조형 10번 확정, playmaker/Roaming 유지. [2026-07-17 재확인] 멘데스 주도 매각 구도 지속(€20-25m), 내부적으로 "이탈 불가피" 기류. 리버풀 경쟁. [2026-07-19 재검증] Football Insider(2티어) 단일 "완전히 열린 기회" 보도만 확인, tier-1 협상 확인 없음. 리버풀·레버쿠젠·사우디(멘드스 경유)까지 경쟁 확대로 빌라 우위 불확실.','https://readastonvilla.com/2026/06/12/aston-villa-transfer-news-pedro-goncalves-sporting-sale-2026/ ; https://footballplace.co.uk/aston-villa-pedro-goncalves-transfer-price-drop/ ; SofaScore API player 895764 (2026-07-12)','MEDIUM — 2티어 단일 관심 보도, 경쟁 확대로 불확실성 상승. [2026-07-19 재검증 하향] (2026-07-20 21시 재검증: 신규 — footballplace/A Bola(포르투갈지, 크로스체크 실패) 경유 스포르팅 호가 €30-40m→€20-25m 급락 보도, 곤살베스 정신건강 발언 이후 구단 내부 이적 "불가피" 판단. tier-1/2(Football Insider 등) 확인 없음 — 크로스체크 미통과로 등급 유지.)','곤살베스');
INSERT INTO transfer_targets VALUES(75,'2026-summer','Pervis Estupiñán','에스투피냔',805465,'AC Milan','LB','LB','HIGH','21000X3100610007200032100',16.10000000000000143,49.10000000000000142,6,6.870000000000000106,'fb_att_wb','Support','fb_att_wb','Support',0.945999999999999953,'좌측면 전 깊이 커버 공격형 레프트백. 실측 6경기(세리에A, 322pt) 중심 tool(16,49). 커널 fit fb_att_wb/Support 0.946 (2위 fb_inverted/Build-Up 0.89). 밀란 아모림 구상 외, 호가 ~€14m. [2026-07-14 야간 재확인] Romano: "AVFC 좌측백 3인 숏리스트 중 상위, 딜 진행중, 협상 계속"(YouTube) — 단 조건 미확정, 데포르티보 라코루냐 경쟁 참전. 디뉴 대체가 아니라 마첸 백업/뎁스 역할로 영입(주전 보장 아님). [2026-07-15 재확인] Matteo Moretto(로마노 채널, 준1티어급): "협상 공식 개시" 확인 — 밀란-빌라 간 클럽 대 클럽 협상 단계 진입. 이적료 격차(€18-20m vs €10-12m)만 남음. 협상 단계 확인으로 HIGH 상향. [2026-07-15 3축+스탯 — 유지] 6경기: 패스 89%·태클 1.3·kp .8 — 견실 전진 LB. att_wb/Support 유지(마첸 07-15 교정 처방과 동일 — 경쟁 구도 명확). [2026-07-17 재확인] Romano(1티어): 개인조건 합의 완료. 클럽간 협상 advanced("non-stop contacts" — Longo), 이적료 격차 €12m vs €18-20m에서 Gazzetta €15m 절충설. 완료 임박 국면. [2026-07-18 재확인] 클럽간 최종 협상 단계 — 밀란 €18-20m vs 빌라 €10-12m에서 €15m 절충 근접(Gazzetta), "다음 주 초 이전 타결" 양측 낙관. 결정적 미팅 수일 내. [2026-07-19 재검증 강화] Romano(1티어, 7/16-17): 빌라가 에스투피냔과 개인조건 합의, 선수도 이적 희망, AC밀란과 이적료 협상 계속. 텔레그래프(2티어)도 advanced 확인. 이적료 격차만 남음(18-20m 밀란 요구 vs 10-13m대 빌라).','Moretto via SempreMilan https://sempremilan.com/moretto-aston-villa-enquire-milan-estupinan ; SofaScore player/805465 (6 Serie A ~2026-05-10)','HIGH — Romano(1티어) 개인조건 합의 확인, 이적료 협상 단계. [2026-07-19 재검증: 기존 HIGH 근거 강화] (2026-07-20 21시 재검증: 등급 유지. Moretto(1티어급)/GiveMeSport(Jacobs) — 개인조건 완전 타결 유지, 이적료만 €10-12m(빌라) vs €18-20m(밀란) 격차로 "one step away". 이번 주말 클럽간 회동으로 타결 시도 보도, 아직 미완료·공식발표 없음.)','에스투피냔');
INSERT INTO transfer_targets VALUES(76,'2026-summer','Antonio Nusa','누사',1121923,'RB Leipzig','LW','LM','MEDIUM-HIGH','13010X6210443002220010000',25.89999999999999858,58.70000000000000284,6,7.25,'wm_wideplm','Attack','wm_wideplm','Attack',0.8810000000000000053,'높고 넓은 좌측 윙어(하프스페이스 인사이드 드리프트). 실측 6경기(분데스리가, 257pt) 중심 tool(26,59). 커널 fit wm_wideplm/Attack 0.881 (2위 wm_insidefwd/Balanced 0.845). 라이프치히 호가 £43~50m, PL 5개팀 경쟁. MEDIUM-LOW에서 상향. [2026-07-15 재확인] Football Insider(2티어): 라이프치히 £50m면 매각 의향 확인, 뉴캐슬 등 경쟁 심화, 재정 부담 우려 지속. [2026-07-15 3축+스탯 — 유지] 6경기: 드리블 1.3·듀얼 4.7·xA .13·kp .8·2골·패스 71% — 기능은 직선 캐리어(플메형 창조 아님, 캐비앗). 움직임 wideplm/Attack .881 최상(insidefwd .845, Δ.036>.03) — 측정최적 유지. [2026-07-17 톱급 스탯 검증] 최근 6경기 xG .05·xA .13·kp .8·2골 + 직전 시즌 4골 3도움/31경기 — 벤치마크(로저스 시즌 xG .30·xA .20·kp 1.9) 대비 산출 전 지표 미달. £50m 밸류는 산출이 아니라 잠재력(21세·월드컵 임팩트) 프리미엄 — "톱 윙어" 후보로는 스탯 근거 부족, 로저스 직대체가 아닌 성장형 투자 프로필. [2026-07-19 재검증] tier-1/2 확인 소스 없음(3티어만: Football Insider원문은 confirm 안됨-재확인 필요, TheHardTackle/FootballFanCast). 라이프치히 매각 압박 없음(계약 2029), 뉴캐슬·아스날·스퍼스·팰리스 경쟁 지속. 등급 유지. [2026-07-20 21시(4차) 재검증] Football Insider(2티어) 복수 보도 — £50m 제안시 수락 가능·빌라뉴캐슬 추격 강화·오퍼 임박. 기존 3티어뿐이던 근거가 2티어로 보강됐으나 등급은 이미 MEDIUM-HIGH — 등급 유지, 근거만 보강.','Football Insider/TEAMtalk/ESPN 관심 보도; SofaScore player/1121923 (6 Bundesliga ~2026-05-16)','MEDIUM-HIGH — [2026-07-14 재확인] 라이프치히 호가 £50m(€50-60m)로 확정, 2029계약이라 "매각 압박 없음"(no immediate pressure to sell) 명시. 경쟁 7클럽으로 확대(뉴캐슬·아스날·토트넘·밀란·아틀레티코·크팰). 빌라 자체 재정 여건상 "£50m는 부담될 수 있다"는 반증 보도 등장 — 등급 MEDIUM-HIGH 유지하되 실현성 리스크 상향 병기. / 2026-07-15 재확인: Football Insider(2티어) £50m 매각 의향 확인, 재정 부담 우려 지속. [2026-07-19 재검증: 등급 유지]','누사');
INSERT INTO transfer_targets VALUES(77,'2026-summer','Johan Manzambi','만잠비',1518931,'SC Freiburg','CM','LDM','CONFIRMED','33414775548X6447877220320',43.60000000000000142,51.79999999999999716,6,7.620000000000000106,'dm_dlp','Roaming','dm_dlp','Roaming',0.8120000000000000551,'완전 box-to-box, 중앙 전역 커버(온아나 대체). 실측 6경기(분데스리가, 363pt) 중심 tool(44,52). 커널 fit LDM dm_dlp/Roaming 0.812 (RDM는 0.544로 약함 → 좌중앙 성향, LDM 전용). 평균 7.62 최상. [2026-07-14 확정] 빌라 합류 확정(사용자 확인). [2026-07-15 재확인] Romano "here we go": €60m+ 구두합의, 개인조건 완료. 뉴캐슬 £49m 구두합의를 히잭. 아직 공식 발표(메디컬) 전 단계. [2026-07-15 3축+스탯 — 유지] 6경기: 듀얼 7.5(후보군 1위)·xG .18·xA .16·태클 1.8·평점 7.40 — 박투박+창조 겸비(오나나 공백 임무에도 부합), dlp/Roaming 유지. [2026-07-17 재확인] 메디컬 완료(7/16), Romano "몇 시간 내 발표". Visit Rwanda 스폰서 관련 잡음(DRC 가족사) 해소, 5년 계약 — 클럽 레코드 £50m+. [2026-07-18 재확인] 공식 발표 완료(7/17 저녁) — £59.5m(€70m) 클럽 레코드, 장기계약. 뉴캐슬 하이잭 최종 성사.','Romano/Ornstein/Sky Germany 하이잭 보도(€70m 합의 임박); SofaScore player/1518931 (6 Bundesliga ~2026-05-16)','CONFIRMED — 합류 확정. 실측 신뢰 HIGH(6경기 전부 45분+, 363pt, fit 0.812). / 2026-07-15: 구단간·개인 합의 완료, 공식 발표만 대기 — CONFIRMED 유지. / 2026-07-18: 구단 공식 발표 — 완료.','만잠비');
INSERT INTO transfer_targets VALUES(82,'2026-summer','Archie Gray',NULL,1142335,'Tottenham Hotspur','MF','RDM','MEDIUM','2022242467255X52657421432',56.52000000000000312,48.25,6,6.650000000000000355,'dm_dlp','Roaming','dm_dlp','Roaming',0.7970000000000000417,'PL/UCL 최근 6경기(45분+, U21 국가대표 경기 제외) 히트맵 299pt, 중앙 우측 편향(tool 56.5/48.3) — RDM 배치시 dm_dlp/Roaming 0.797, LDM 배치시 0.528로 하락해 우측 적합 확인. [2026-07-15 재확인] 도르트문트·맨유·첼시 포함 다자 경쟁 지속, 빌라 "확정 관심" 보도(경쟁사 다수). [2026-07-15 3축+스탯 — 유지] 6경기: 듀얼 1.5·태클 .7(피벗 기능 표본 약 — 스퍼스 유틸 기용 영향, 캐비앗)·xA .11·kp 1.0. dlp/Roaming 유지. [2026-07-19 재검증] 토트넘이 최종전 승리로 강등 면함 — 강등시에만 실현된다던 이적 전제 소멸. tier-1/2 빌라 구체 추진 확인 안 됨(TeamTalk 모니터링 수준). 빌라 실제 우선순위는 서머빌·베리발/와튼으로 확인.','teamtalk.com; footballfancast.com; spurs-web.com; SofaScore API player 1142335 (수집 2026-07-13)','MEDIUM — 강등 회피로 매각 압박 소멸, 빌라 추진 근거 약화. [2026-07-19 재검증 하향]','그레이');
INSERT INTO transfer_targets VALUES(85,'2026-summer','Martin Baturina','마르틴 바투리나',1090019,'Como','AM','CAM','MEDIUM-HIGH','31114757647X7526531211111',42.82000000000000028,57.32000000000000028,6,7.25,'cam_playmaker','Build-Up','cam_playmaker','Build-Up',0.6550000000000000266,'빌라 영입팀이 €50-55m 공식 오퍼 제출, 코모측 €80m 요구로 거절(2030계약 장기 보유); 바이에른도 경쟁. tier-1(로마노/오른스틴/스카이) 미확인, FootballInsider247·TheHardTackle·GiveMeSport(2티어급) 복수가 오퍼·거절 단계까지 수렴해 MEDIUM-HIGH. 실측: Serie A 최근 6경기(45분+, 컵 1경기 포함) 431 히트포인트, cam_playmaker/Build-Up 적합 0.655(중간) — 중앙 공격형 미드필더로 창조적 플레이메이커 성향과 부합. [2026-07-15 재확인] 빌라가 €50-55m 실제 오퍼 제출 확인(Sport Witness/Sky Italia 경유), 코모가 거절하며 €80m 요구. 맨유·바이에른·토트넘도 경쟁. 실제 오퍼 제출·거절이라는 협상 단계 행위 확인 — MEDIUM-HIGH로 상향. [2026-07-15 3축+스탯 — focus 교정 Balanced→Build-Up] 6경기 스탯: kp 3.8(후보군 1위)·xA .15·드리블 2.0·듀얼 4.8 — 엘리트 딥 창조자. 움직임 playmaker/Build-Up .655 최상(Balanced <.57) — Build-Up으로 교정. [2026-07-17 재확인] 코모 €80m 고수로 교착 지속. 스퍼스·바이에른·맨유 경쟁 확대. Sky Italia: 빌라 관심 유지. [2026-07-19 재검증] Moretto(로마노 협력·1티어급)가 빌라+토트넘 정식 문의 확인, Di Marzio(이탈리아 1티어급)는 코모의 80m 요구·오퍼 거절 확인. 단 애슬레틱(Tanswell, 1티어)은 빌라 예산 한도 약 40m로 밸류 갭 큼 — 등급 유지, 가격 격차 리스크 병기.','https://www.footballinsider247.com/aston-villa/martin-baturina-everything-you-need-to-know-about-69m-rated-aston-villa-target-as-bid-submitted ; https://thehardtackle.com/transfer-news/2026/07/07/aston-villa-tottenham-told-to-pay-e80-million-to-sign-martin-baturina/ ; https://www.givemesport.com/aston-villa-martin-baturina-transfer-bid-emery/ (2026-07-14 evening watch)','MEDIUM — [2026-07-14 재확인] 빌라의 €50-55m 공식 오퍼가 코모에 거절당함, 코모는 €80m 요구하며 "매각 불가(non-transferable)" 입장. The Athletic(1티어, Tanswell)은 빌라 SCR상 선수 1명에 £40m 이상 못 쓴다고 명시 — 코모 요구액과 격차가 2배 가까이 벌어져 현실성 하향. MEDIUM-HIGH에서 하향. / 2026-07-15: 실제 오퍼 제출·거절 확인(협상 단계)로 상향. [2026-07-19 재검증: 등급 유지, 밸류 갭(빌라 40m 한도 vs 코모 80m 요구) 리스크 확인]','바투리나');
INSERT INTO transfer_targets VALUES(88,'2026-summer','Matías Soulé','마티아스 소울레',1082406,'AS Roma','FW','RM','MEDIUM-HIGH','101131114X011331012100001',72.3299999999999983,61.42999999999999972,6,6.919999999999999929,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.9050000000000000266,'로마 FFP 압박(€60m 자본이득 필요)으로 매각 후보, 본인은 프리미어리그·빌라 이적 희망(가제타 델로 스포르트). 왓킨스 다음 레벨을 위한 연계형 우측 자원. 실측: Serie A 최근 6경기(45분+, 2026-04~05, 336pt) 우측 강한 편향(tool_x 72.3), wm_insidefwd/Balanced 0.905 — RM 후보 중 최고 수준. [2026-07-15 재확인] 협상 진행 중이나 공식 오퍼 아직 없음, €40m부터 협상 개시 필요. 로마는 그린우드 자금 마련 위해 매각 필요성 증가. [2026-07-15 3축+스탯 — 유지] 6경기: xG .10·xA .10·kp 1.5·패스 86% — 균형 양방형, insidefwd/Balanced 유지(.905 최상 재확인). [2026-07-19 재검증] 로마 가스페리니 감독이 소울레에 회의적 태도라는 보도(3티어), 35-40m 매각 가능성 — 빌라가 경쟁 중 최선두로 계속 거론되나 tier-1 협상 확인 없음. 등급 유지.','footballinsider247.com; gazzetta.it(via Sport Witness); readastonvilla.com; thehardtackle.com; SofaScore API player 1082406 (수집 2026-07-14)','MEDIUM-HIGH — [2026-07-14 재확인] 로마 6/30 FFP 데드라인은 지났으나 여전히 매각 후보로 거론, 도르트문트가 "serious" 경쟁자로 남음. 빌라·본머스는 아직 "물밑 타진" 수준. 등급 유지. / 2026-07-15 재확인: 협상 진행 중이나 공식 오퍼 아직 없음, 등급 유지. [2026-07-19 재검증: 등급 유지]','소울레');
INSERT INTO transfer_targets VALUES(89,'2026-summer','Lucas Bergvall','루카스 베르그발',1391251,'Tottenham Hotspur','CM/AM','CAM','MEDIUM-HIGH','201340237821256135X600220',66.20000000000000284,52.5,6,6.450000000000000177,'cam_halfwinger','Balanced','cam_halfwinger','Balanced',0.5390000000000000346,'티엘레만스 맨유 이적(바이아웃 발동, CONFIRMED)으로 생긴 중원 공백 대체 후보. Football Insider(2티어): 첼시와 함께 "open race", 1월에도 접촉했으나 거절당함. 본인이 스퍼스에 이적 희망 의사 전달(구단 공식 컨택은 아직 없음). [2026-07-15 재확인] David Ornstein(Athletic, 1티어): 스퍼스가 빌라의 과거 오퍼를 즉각 거절했음을 확인 — 즉, 실제 접촉·오퍼가 있었음을 1티어가 실증. 다만 Sky Sports Michael Bridge(1티어)는 "이번 여름 잔류 통보"로 상충. 실제 이적 시도는 확인됐으나 성사 불투명 — MEDIUM-HIGH로 상향. [2026-07-15 실측] SofaScore 최근 6경기(PL/UCL, 45분+: 22-03·20-01·07-01·28-12·20-12·02-12, 스퍼스 로테이션 멤버라 표본기간이 긺) 히트맵 수집. 중앙 우측 치우침(66.2,52.5) — CAM치고는 다소 깊은 위치, cam_halfwinger/Balanced 코사인 0.539로 중간 적합(참고: dm_holding/Roaming 계열이 0.612로 더 높아 실제로는 딥 플레이메이커에 가까운 풋프린트). [2026-07-15 3축+스탯 — 유지] 6경기: kp .3·xA .01·듀얼 1.5·평점 6.30 — 로테이션 표본이라 기능 신호 약(캐비앗 추가). CAM 적합 .539 중간, DM계열 .612 우세 병기 유지. [2026-07-17 재확인] 노팅엄 포레스트 경쟁 합류, 예상가 £50m. 스퍼스는 매각 체념 기류(1월 빌라·첼시 문의 거절에서 선회). [2026-07-19 재검증] Romano(1티어): 베리발 본인 이적 희망 확인되나 최근 언급은 노팅엄포레스트·뉴캐슬 중심 — 빌라는 Football Insider(2티어) 단독. Sky Sports(1티어, Bridge)는 여전히 잔류 통보 유지. 등급 유지하되 하향 리스크 관찰 필요. [2026-07-20 21시(4차) 재검증] TeamTalk(2티어): 노팅엄포레스트가 베리발 경쟁에 가세, 빌라는 에스투피냔 협상과 병행 진행 — 기존 구도(포레스트·뉴캐슬 중심)와 일치, 등급 유지.','Football Insider(via football365, 2026-07-14) — "open race" 보도; TeamTalk/readastonvilla — 티엘레만스·와튼 대안으로 거론; 상충: Sky Sports 기자 Michael Bridge(1티어) — "이번 여름 잔류 통보받음" 보도 ; SofaScore API player 1391251 (2026-07-15, PL/UCL 최근 6경기 45분+)','MEDIUM — 실측 완료(2026-07-15: fit cam_halfwinger/Balanced 0.539, DM계열 0.612 우세 병기). 2티어 복수 관심 보도이나 1티어(Sky Sports Michael Bridge)가 잔류 보도로 상충 — 협상 단계 아님, 슬롯(CAM)은 잠정 배치. / 2026-07-15: 1티어(Ornstein) 과거 오퍼·거절 확인으로 상향, 단 1티어(Bridge) 잔류 보도와 상충 지속. [2026-07-19 재검증: 등급 유지, 단 최신 tier-1 초점이 포레스트/뉴캐슬로 이동 — 하향 주의]','베르그발');
INSERT INTO transfer_targets VALUES(90,'2026-summer','Crysencio Summerville','크리스헨시오 서머빌',917005,'West Ham United','LW/RW','LM','MEDIUM-HIGH','74100X5200832107311011100',22.80000000000000071,57.20000000000000284,6,7.230000000000000426,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.8449999999999999734,'빌라의 "톱 타깃"으로 시즌 전 윙어 영입 최우선 순위. 로마가 £34m 오퍼 거절당함, 맨유·PSG도 관심 표명. 웨스트햄은 강등 후 자금 필요하나 £43m 요구 고수, 빌라 재정 여건상 부담. [2026-07-15 실측] SofaScore 최근 6경기(45분+, PL: Leeds·Newcastle·Arsenal·Brentford·Everton·CrystalPalace) 히트맵 수집. 좌측 고정 포지션(y 57-99, 전 경기 좌측), 중심좌표(22.8,57.2) — 좌측 중앙~공격3분의1. wm_winger/Balanced 커널과 코사인 0.82로 최적 적합. [2026-07-15 3축+스탯 — 교정 winger/Balanced→insidefwd/Balanced] 6경기 스탯: xA .23·kp 1.2·듀얼 8.2(후보군 1위)·드리블 2.8 — 엘리트 캐리어+창조 겸비 인버티드형. 움직임 insidefwd/Balanced .845 vs winger/Balanced .82(Δ.025 동률권) — 기능축 타이브레이크. [2026-07-17 재확인] the72/Football Insider: 빌라 추적 지속, 월드컵 2골(일본·스웨덴전)로 웨스트햄 요구액 £50m까지 상승. 맨유(래시포드 거취 종속)·로마 경쟁. 본인은 마이애미 휴가 후 결정 방침. [2026-07-19 재검증] 버밍엄메일(John Townley, 2티어) 구체적 관심·43m 밸류 재확인. 로마가 45m 오퍼, 선수 연봉 협상 중(6m 희망 vs 로마 4.5m 제시) — 월요일(7/20)까지 결정 시한 보도(3티어). 베팅 오즈는 여전히 로마 1/2 우세. 등급 유지, 분기점 임박. [2026-07-20 21시(4차) 재검증] Sky Sports Paper Talk(1티어 매체 경유)·Football Insider(2티어) "odds tumble" 복수 보도로 빌라 추진 신호 강화 — MEDIUM에서 MEDIUM-HIGH로 상향. 단 로마가 여전히 배당률 우세(1/2), 협상 완료 아님.','Football Insider(footballinsider247, 2026-07-15) — "Villa top target, West Ham could have no choice but to let him go"; westhamzone.com — 경쟁 심화 보도 ; SofaScore API player 917005 (2026-07-15, PL 최근 6경기 45분+)','MEDIUM — 2티어(Football Insider) 구체적 관심 보도로 크로스체크 통과, 협상 단계 도달 전. 실측 완료: wm_winger/Balanced 0.82(HIGH 적합). [2026-07-19 재검증: 등급 유지, 7/20 결정 시한 — 다음 스캔 필수 재확인]','서머빌');
INSERT INTO transfer_targets VALUES(91,'2026-summer','João Palhinha',NULL,364612,'Bayern Munich','DM','LDM','MEDIUM-HIGH','002112323345365465X611221',53.70000000000000284,44.0,6,6.919999999999999929,'dm_holding','Ball-Winning','dm_widehalf','Build-Up',0.6800000000000000488,'틸레망스 공백+오나나/카마라 부상 대비 #6. 빌라 loan+option €25m 제안 준비 보도. 파괴형(플레이메이커 아님) — 만잠비와 역할 상보. [2026-07-17 실측+3축] SofaScore 최근 6경기(45분+): 태클 3.3(후보군 1위)·듀얼 6.3·인터셉트 1.5·kp .5·xA .01 — 순수 파괴자/볼위너(서사 "destroyer" 실측 일치). 기능축 → dm_holding/Ball-Winning(카마라형). LDM 배치 코사인 .68로 우측(.75)보다 열세. [2026-07-19 재검증] Romano(1티어): 팔리냐는 빌라 경영진·에메리가 실제로 검토 중인 이름, 단 공식 오퍼·협상은 아직 없음. 메디컬설이 돌았다 24시간 내 부인되는 등 유동적. 벤피카 임대+바이옵션 구조 vs 빌라 완전영입 선호로 바이에른과 조율 중. [2026-07-20 21시(4차) 재검증] Romano(1티어, 재인용): 만잠비 이후 빌라가 팔리냐 딜을 논의 중. 단 바이에른 담당기자 Plettenberg(1티어급)는 "합의 없음, 프리시즌 잔류"로 명시 반박 — 진전과 반박 공존, 등급 유지.','https://www.transferfeed.com/clubs/aston-villa/15; Record(PT); GiveMeSport; SportsMole','MEDIUM-HIGH — Romano(1티어) 클럽 차원 검토 확인(협상 전 단계). [2026-07-19 재검증 상향]','팔리냐');
