INSERT INTO transfer_targets VALUES(106,'2026-summer','Nicolas Jackson','니콜라스 잭슨',1085381,'Chelsea','ST','ST','MEDIUM-HIGH','154304X273235212301000100',44.25999999999999802,64.45999999999999374,6,6.549999999999999823,'st_advanced','Support','st_advanced','Support',0.6310000000000000053,'첼시가 바이에른 임대 옵션 미행사로 복귀시켜 매각 방침 확정, 에메리와 비야레알 시절 인연. 실측: 분데스리가+월드컵 혼합 6경기(45분+, 276pt, 클럽 3+대표팀 3), st_advanced/Support 0.631 — 왓킨스·기라시와 동일 계열, 스피드·프레싱형. [2026-07-19 재검증] Sky Sports(1티어)가 오늘도 관심 재확인("exploring conditions"), 단 여전히 오퍼·본격협상 없음. 첼시 70m 밸류에 하드 스탠스, 맨유·나폴리도 문의. 로저스 스왑안은 가치 격차로 비현실적 재확인. 등급 유지.','https://www.skysports.com/football/news/11677/13415336/nicolas-jackson-transfer-news-aston-villa-interested-in-signing-chelsea-striker-after-exploring-conditions-of-deal ; https://www.givemesport.com/newcastle-transfer-news-aston-villa-chelsea-nicolas-jackson-fabrizio-romano-exclusive/ (2026-07-19)','MEDIUM-HIGH — Sky Sports(1티어) "관심 확인, 조건 탐색 중" 보도로 크로스체크 통과. 단 Simon Phillips(3티어)에 따르면 "탐색적" 수준·정식 오퍼 없음, 빌라 예산 이미 소진되어 €70m대 밸류에이션은 현실성 낮음(로저스 스왑 제안은 가치 격차로 불가). 실측 신뢰 MEDIUM(표본 절반이 국가대표팀 경기). [2026-07-19 재검증: 등급 유지, Sky Sports 1티어로 재확인] (2026-07-20 21시 재검증: 신규 — GiveMeSport(Ben Jacobs, 2티어급 미만/크로스체크 불충분) 보도로 잭슨 본인이 첼시 잔류·알론소 체제 하 입지 경쟁 선호 결정, 첼시 프리시즌 호주투어 합류 예정. thehardtackle(3티어)는 여전히 협상 지속 보도로 상충. 1티어(Sky Sports/Romano) 재확인 없음 — 크로스체크 미충족으로 등급 유지하되 하방 리스크로 병기.)','잭슨');
INSERT INTO transfer_targets VALUES(107,'2026-summer','Leo Scienza','레오 시엔자',1386651,'Southampton','LM','LM','MEDIUM','93112X5210632004311011000',24.87000000000000099,63.46000000000000085,6,6.769999999999999574,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.8780000000000000026,'챔피언십 승격 주역(10골10도움), 레온 베일리 대체 옵션으로 거론. 실측: 챔피언십 6경기(45분+, 375pt) 좌측 강한 편향(tool 24.9/63.5), wm_insidefwd/Balanced 0.878 — 서머빌·트로사르와 유사 계열. [2026-07-19 재검증] TeamTalk(2티어)은 구체적 관심 확인되나 협상 단계 언어 없음(초기 논의/모니터링). 어제 MEDIUM-HIGH 판정은 과대평가로 재검증 - 정정. 레알 베티스·소시에다드·팔메이라스·플라멩구까지 경쟁 확대. [2026-07-20 21시(4차) 재검증] TheHardTackle(등급외): 사우스햄튼이 £35m 확정 요구가 발표. 1~2티어 확인 없어 등급 유지.','https://www.footballinsider247.com/leo-scienza-aston-villa-interest-spells-the-end-for-leon-bailey-southampton-to-accept-exit/ ; https://www.teamtalk.com/aston-villa/aston-villa-summer-swoop-southampton-winger-leo-scienza ; https://www.footballfancast.com/aston-villa-now-actively-discussing-deal-to-sign-leo-scienza-southampton/ (2026-07-19)','MEDIUM — 2티어 관심 확인, 협상 단계 아님(전일 MEDIUM-HIGH 판정 정정). [2026-07-19 재검증 하향 정정]','시엔자');
INSERT INTO transfer_targets VALUES(108,'2026-summer','Jonathan Rowe','조나단 로우',1065261,'Bologna','LW','LM','MEDIUM-HIGH','46200X5211731113110000000',27.30000000000000071,66.0799999999999983,6,7.179999999999999716,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.8970000000000000195,'에메리가 직접 지목한 공격 보강 프로필("one of the profiles"), 세리에A 볼로냐에서 8골5도움(42경기, 유로파리그 4골 포함) — 빌라 상대 유로파리그 8강에서 극장골(91분 오버헤드킥)로 직접 눈도장. 갈라타사라이·첼시와 경쟁, €40m(£35m) 필요. 실측: 세리에A+유로파리그 6경기(45분+, 316pt, 평균평점 7.18 — 빌라전 9.1 포함) 좌측 강한 편향(tool 27.3/66.1), wm_insidefwd/Balanced 0.897 — 서머빌·트로사르와 동일 계열. [2026-07-20 21시(4차) 재검증] 등급외 소스(footballinsider247·thehardtackle): 볼로냐 호가 €40m→€45m 상향, 첼시 £32m 오퍼 검토설. 1~2티어 직접 확인 없어 등급 유지.','https://www.footballinsider247.com/aston-villa-jonathan-rowes-bologna-exploits-vs-napoli-show-why-hes-a-nailed-on-target-for-unai-emery/ ; https://readastonvilla.com/2026/05/25/aston-villa-jonathan-rowe-bologna-transfer-2026/ ; SofaScore API player 1065261 (수집 2026-07-19)','MEDIUM-HIGH — Football Insider(2티어) "nailed-on target" 확인 + 3티어 다수(TheHardTackle/Yahoo/SportWitness) 수렴, tier-1 미확인. 첼시·갈라타사라이 등 경쟁 있으나 본인 PL 복귀 희망 공언. 실측 HIGH(6경기 전부 45분+, 316pt).','로우');
INSERT INTO transfer_targets VALUES(109,'2026-summer','Roony Bardghji','로니 바르드기',1162107,'FC Barcelona','RW','RM','MEDIUM','000230003X000140001300001',83.39000000000000056,61.97999999999999688,6,6.530000000000000248,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.945999999999999953,'라민 야말에 밀려 출전시간 부족(28경기 842분), 본인이 바르사에 이적 희망 표명. 6+클럽(빌라·리즈·에버턴·선덜랜드·브라이튼·브렌트포드) 경합, 바르사는 €10m 저가 매각도 검토하나 최근엔 €20-25m 요구설. 임대 선호(아약스가 무옵션 임대 제시) vs 완전이적(바이백 조항) 논의 중. 실측: 전부 교체출전 표본(6경기 45+, 46-67분, 294pt), 우측 터치라인 강고정(tool 83.4/62.0, 중앙 드리프트 거의 없음) — wm_insidefwd/Balanced 0.946(RM 후보 최고 수준). 다만 산출 저조(xG.04·0골·xA.13, 전부 교체 표본이라 편향 가능) — "당장 쓸 선수"라기보다 잠재력 베팅. 자기진영 복귀 비중 17.9%로 다소 낮음(뎁스 옵션 고려 시 참고).','https://thehardtackle.com/transfer-news/2026/07/17/everton-aston-villa-leeds-united-make-move-for-roony-bardghji/ ; https://footballplace.co.uk/aston-villa-roony-bardghji-transfer-barcelona/ ; Mundo Deportivo/Sport(스페인 스포츠 일간지, 2티어급) 경유 SportWitness (2026-07-19)','MEDIUM — Sport·Mundo Deportivo(스페인 주요 스포츠지, 2티어급) 경유 "매각 검토·본인 희망" 확인, 6클럽+ 경쟁으로 빌라 우위 불확실. 1티어 미확인. 10일 내 결정 시한 보도(3티어). 실측 신뢰 MEDIUM(전부 교체출전 표본).','바르드기');
INSERT INTO transfer_targets VALUES(110,'2026-summer','Abdessamad Ezzalzouli','아브데 에살줄리',NULL,'Real Betis','LW','LM','MEDIUM',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'[2026-07-20 신규] 레알 베티스 좌윙(모로코 대표) — 에메리 선호 후보, 로저스(첼시 £117m 확정) 좌측 대체 물망. 이적료 €40m(£35m) 거론, 방출조항 €60m·계약 2029, 바르사가 재판매 20% 보유. 뉴캐슬과 경쟁(고든 바르사행 대체로 뉴캐슬이 더 적극적). 캐비앗: 6d 전 기준 ''양 클럽 모두 베티스에 공식 접촉 없음''(모니터링 단계), 양 팀 CL 병행 예상 → 벤치 감수 가능성 낮음, 보도 다수가 5~6월자. 실측 PENDING.','TransferFeed(6d) ; Diario de Sevilla — 빌라 관심·뉴캐슬 경쟁 ; Sport via Sport Witness — €40m·베티스 현금화 수용 ; Football Insider — 로저스 대체 물색 (2026-05~06 보도)','MEDIUM — 2티어 복수(Diario de Sevilla, Sport, Football Insider) 구체 관심이나 공식 접촉 전무·뉴캐슬 우위·보도 다소 오래됨. PENDING MEASUREMENT (SofaScore 실측 미수행).','에살줄리');
INSERT INTO transfer_targets VALUES(111,'2026-summer','Nick Woltemade','닉 볼테메데',NULL,'Newcastle United','ST','ST','MEDIUM','11221485X3322313522101100',45.60000000000000142,56.79999999999999716,6,6.679999999999999716,NULL,NULL,'st_false9','Build-Up',0.7069999999999999619,'2티어 복수(Sports Mole, Express & Star) 관심 보도, 도르트문트·아틀레티코 경쟁. 뉴캐슬 호가 €65m로 빌라 재정상 회의론 존재(로저스 매각 자금 전제). 협상 단계 아님.','https://www.sportsmole.co.uk/football/newcastle-united/transfer-talk/news/newcastle-set-woltemade-asking-price-amid-villa-european-giants-interest_599733.html ; https://www.expressandstar.com/sport/football/aston-villa/transfer-column-aston-villa-linked-with-newcastle-striker-nick-woltemade-8752571 (2026-07-20 수집)','실측 완료(2026-07-20): fit st_false9/Build-Up 0.707 — 링크형 플레이 성향(단순 침투형 아님) 실측 확인, 뉴캐슬 로테이션 표본(45분+ 6경기, 평균 6.68). 2티어 복수(Sports Mole, Express & Star) 관심 보도, 협상 전 단계·가격 장벽 존재.','볼테메데');
INSERT INTO transfer_targets VALUES(112,'2026-summer','El Hadji Malick Diouf','엘 하지 말리크 디우프',NULL,'West Ham United','LB','LB','MEDIUM','210007210051000X200042100',15.40000000000000035,44.70000000000000285,6,6.929999999999999716,NULL,NULL,'fb_att_wb','Support',0.8910000000000000142,'디뉴 PSG 이적 확정에 따른 좌측풀백 대체 후보. Football Insider(2티어) 에버턴 등 PL 클럽 관심 확인, West Ham은 £30m 이하 거절 방침(구단측 매각 의사 없음). 빌라 공식 오퍼 없음.','https://www.hammers.news/transfer-news/west-ham-braced-for-aston-villa-bid-for-el-hadji-malick-diouf-as-psg-close-in/ (2026-07-20 수집)','실측 완료(2026-07-20): fit fb_att_wb/Support 0.891(HIGH 적합) — 웨스트햄 최근 6경기(45분+, 전부 90분 근접) 실측, 평균 6.93. 공격형 풀백 성향 확인(디뉴 대체 적합). 웨스트햄 £30m 이하 거절 방침·챔피언십 잔류 선호, 공식 오퍼 없음.','디우프');
INSERT INTO transfer_targets VALUES(113,'2026-summer','Dan Burn','댄 번',NULL,'Newcastle United','LCB','LCB','MEDIUM','102003310075200X741063300',25.89999999999999858,38.89999999999999858,6,6.530000000000000248,NULL,NULL,'cb_bpd','Aggressive',0.8529999999999999805,'TeamTalk(2티어) 디뉴 대체 후보로 번+에스투피냔 병기 확인. 콘사 대체(아스날행 대비) 목적으로도 언급되나 콘사는 우측 수비수로 포지션 불일치 캐비앗. 협상 전 단계.','https://www.teamtalk.com/aston-villa/villanswant-former-prem-left-back-estupinan-burn (2026-07-20 수집)','실측 완료(2026-07-20): fit cb_bpd/Aggressive 0.853(HIGH 근접) — 뉴캐슬 최근 6경기(45분+) 실측, 평균 6.53. 좌측 CB 포지셔닝 확인(콘사는 우측이라 직접 대체는 포지션 불일치, 디뉴 대체 또는 좌측 뎁스 후보로 적합). TeamTalk(2티어) 확인, 협상 전 단계.','번');
INSERT INTO transfer_targets VALUES(114,'2026-summer','Marcus Tavernier','마커스 태버니어',NULL,'AFC Bournemouth','RM','LM','MEDIUM-HIGH','24101X4221421104100021000',28.89999999999999858,59.70000000000000284,6,7.169999999999999929,NULL,NULL,'wm_insidefwd','Balanced',0.8639999999999999903,'로저스 대체 목적으로 2티어 복수(TeamTalk "hijack", Sports Mole "enquire") 접촉 확인 보도됐으나, 실측 결과 본머스에서 좌측(cx=28.9) 위주로 뛰어 RM 슬롯과 불일치 — 실측 기준 LM으로 정정(기사 서사보다 실측 우선, CLAUDE.md 규칙3). 리버풀·풀럼도 경쟁, 본머스 2029계약 근거로 매각 거부. [2026-07-20 21시(4차) 재검증] TeamTalk(2티어): 빌라가 풀럼의 접근을 제치고(hijack) 추진한다는 보도로 경쟁 심화 확인, 본머스는 매각 대상 아님 입장 재확인 — 등급 유지.','https://www.teamtalk.com/news/liverpool-aston-villa-hijack-fulham-move-marcus-tavernier-perfect-harry-wilson-heir ; https://www.sportsmole.co.uk/football/bournemouth/transfer-talk/news/villa-fulham-enquire-over-move-for-bournemouth-star_600420.html (2026-07-20 수집)','실측 완료(2026-07-20): fit wm_insidefwd/Balanced 0.864(HIGH 적합) — 본머스 최근 6경기(45분+) 실측, 평균 7.17. 좌측 위주 실측(RM 적합도 0.16로 사실상 불일치) → 슬롯 LM으로 정정.','태버니어');
INSERT INTO transfer_targets VALUES(117,'2026-summer','Ngal''ayel Mukau','응갈아엘 무카우',NULL,'LOSC Lille','RDM','RDM','MEDIUM','000230015X001360011200100',78.70000000000000284,60.0,6,6.799999999999999823,NULL,NULL,'dm_dlp','Roaming',0.6460000000000000186,'토트넘·에버턴·브라이턴 등 경쟁 다수, TeamTalk(2티어) "extensive scouting" 확인. 릴 매각 저항(€40m 요구 vs 시장가 €12m). 기사상 "좌풀식 미드필드 앵커"로 묘사되나, 실측(cx=78.7)은 강한 우측·전진 편향 — LDM은 사실상 불일치(적합도 0.097)로 제외, RDM(로밍형 DLP)만 유지.','https://www.teamtalk.com/news/ngalayel-mukau-transfer-news-tottenham-aston-villa-everton-race-ignites (2026-07-20 수집)','실측 완료(2026-07-20): fit dm_dlp/Roaming 0.646(MEDIUM 적합) — 릴 최근 6경기(45분+) 실측, 평균 6.8. 실측 위치가 예상(좌측 앵커)과 달리 우측·전진 편향 강함(RM급 WM 적합도 0.94) — DM보다 박스투박스/로밍 성향일 가능성. 슬롯은 RDM으로 한정.','무카우');
INSERT INTO transfer_targets VALUES(118,'2026-summer','Noah Atubolu','노아 아투볼루',NULL,'SC Freiburg','GK','GK','MEDIUM',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'에미 마르티네스 유벤투스행 재점화설과 맞물려 대체 GK 후보로 부상. 프라이부르크 계약 만료 1년 전(2027년 여름), €20m 안팎 이적료 예상. Bournemouth·Inter·Frankfurt·Real Sociedad·Hull 등과 경쟁 다자구도, 빌라 확정 우위 아님.','Sky Sport Deutschland(獨 Sky, 재인용 다수) - https://www.football365.com/news/aston-villa-intense-battle-german-goalkeeper-atubolu-martinez-move-on ; TeamTalk(2티어, 마르티네스 대체 프레이밍) - https://www.teamtalk.com/aston-villa/villans-icon-emiliano-martinez-tipped-exit-noah-atubolu-link','PENDING MEASUREMENT (헤드리스 실행, SofaScore 실측 미수행). 참고: DB의 마르티네스 유벤투스 유출설은 기존에 로마노(1티어) 확인 잔류로 DEAD 처리됨 — 이번 TeamTalk 재점화 보도는 2티어 단일소스로 기존 DEAD 판정을 뒤집기엔 근거 부족, 마르티네스 상태는 변경하지 않음.','아투볼루');
